     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import ReactMarkdown from 'react-markdown';
    21→
    22→export const AITerminal: React.FC = () => {
    23→  const {
    24→    isOpen,
    25→    apiKey, // Legacy Gemini key
    26→    model: _model, // Legacy model (unused)
    27→    activeProvider,
    28→    activeModel,
    29→    providers,
    30→    encryptionPassword,
    31→    isPasswordExpired,
    32→    fallbackEnabled,
    33→    messages,
    34→    isStreaming,
    35→    setOpen,
    36→    setActiveProvider,
    37→    addMessage,
    38→    clearMessages,
    39→    setStreaming,
    40→  } = useTerminalStore();
    41→
    42→  const [input, setInput] = useState('');
    43→  const [streamingContent, setStreamingContent] = useState('');
    44→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    45→  const [showModelSelector, setShowModelSelector] = useState(false);
    46→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    47→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    48→
    49→  const messagesEndRef = useRef<HTMLDivElement>(null);
    50→  const inputRef = useRef<HTMLTextAreaElement>(null);
    51→
    52→  // Initialize provider router
    53→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
    54→    // Fallback notification callback
    55→    setFallbackNotification(
    56→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
    57→    );
    58→    setTimeout(() => setFallbackNotification(null), 5000);
    59→  }));
    60→
    61→  // Auto-scroll to bottom when messages change
    62→  useEffect(() => {
    63→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    64→  }, [messages, streamingContent]);
    65→
    66→  // Focus input when terminal opens
    67→  useEffect(() => {
    68→    if (isOpen) {
    69→      inputRef.current?.focus();
    70→    }
    71→  }, [isOpen]);
    72→
    73→  // Initialize AI service with API key (legacy Gemini)
    74→  useEffect(() => {
    75→    if (apiKey) {
    76→      aiTerminalService.setApiKey(apiKey);
    77→    }
    78→  }, [apiKey]);
    79→
    80→  // Configure router with active provider and model
    81→  useEffect(() => {
    82→    router.updateConfig({
    83→      primaryProvider: activeProvider,
    84→      primaryModel: activeModel,
    85→      fallbackEnabled: fallbackEnabled,
    86→    });
    87→  }, [activeProvider, activeModel, fallbackEnabled, router]);
    88→
    89→  // Initialize provider API keys from encrypted storage
    90→  useEffect(() => {
    91→    const initializeApiKeys = async () => {
    92→      if (encryptionPassword && !isPasswordExpired()) {
    93→        const allProviders = router.getAllProviders();
    94→        for (const [providerId, provider] of Object.entries(allProviders)) {
    95→          const providerConfig = providers[providerId];
    96→          if (providerConfig && providerConfig.encryptedApiKey) {
    97→            try {
    98→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
    99→              if (decryptedKey) {
   100→                provider.setApiKey(decryptedKey);
   101→              }
   102→            } catch (error) {
   103→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   104→            }
   105→          }
   106→        }
   107→      }
   108→    };
   109→
   110→    initializeApiKeys();
   111→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   112→
   113→  // Keyboard shortcuts
   114→  useEffect(() => {
   115→    const handleKeyDown = (e: KeyboardEvent) => {
   116→      // Cmd/Ctrl + Shift + A to toggle terminal
   117→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   118→        e.preventDefault();
   119→        setOpen(!isOpen);
   120→      }
   121→      // Escape to close terminal (when open)
   122→      if (e.key === 'Escape' && isOpen) {
   123→        e.preventDefault();
   124→        setOpen(false);
   125→      }
   126→    };
   127→
   128→    document.addEventListener('keydown', handleKeyDown);
   129→    return () => document.removeEventListener('keydown', handleKeyDown);
   130→  }, [isOpen, setOpen]);
   131→
   132→  const handleSubmit = async (e: React.FormEvent) => {
   133→    e.preventDefault();
   134→    if (!input.trim() || isStreaming) return;
   135→
   136→    const userMessage = input.trim();
   137→    setInput('');
   138→
   139→    // Check if any provider is configured
   140→    const configuredProviders = router.getConfiguredProviders();
   141→    if (configuredProviders.length === 0) {
   142→      addMessage({
   143→        role: 'system',
   144→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   145→      });
   146→      return;
   147→    }
   148→
   149→    // Check if active provider is configured
   150→    const activeProviderObj = router.getProvider(activeProvider);
   151→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   152→      addMessage({
   153→        role: 'system',
   154→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   155→      });
   156→      return;
   157→    }
   158→
   159→    // Add user message
   160→    addMessage({
   161→      role: 'user',
   162→      content: userMessage,
   163→    });
   164→
   165→    // Start streaming
   166→    setStreaming(true);
   167→    setStreamingContent('');
   168→
   169→    try {
   170→      // Send message using router (with automatic fallback)
   171→      const response = await router.sendMessage({
   172→        prompt: userMessage,
   173→        conversationHistory: messages.map((msg) => ({
   174→          role: msg.role as 'user' | 'assistant' | 'system',
   175→          content: msg.content,
   176→        })),
   177→        stream: true,
   178→        onChunk: (chunk) => {
   179→          setStreamingContent((prev) => prev + chunk);
   180→        },
   181→      });
   182→
   183→      // Add complete assistant message with provider/model metadata
   184→      addMessage({
   185→        role: 'assistant',
   186→        content: response.content,
   187→        provider: response.provider || activeProvider,
   188→        model: response.model || activeModel,
   189→      });
   190→    } catch (error: any) {
   191→      addMessage({
   192→        role: 'system',
   193→        content: `❌ Error: ${error.message || 'Unknown error occurred'}`,
   194→      });
   195→    } finally {
   196→      setStreaming(false);
   197→      setStreamingContent('');
   198→    }
   199→  };
   200→
   201→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   202→    if (e.key === 'Enter' && !e.shiftKey) {
   203→      e.preventDefault();
   204→      handleSubmit(e);
   205→    }
   206→  };
   207→
   208→  if (!isOpen) return null;
   209→
   210→  return (
   211→    <div
   212→      className={`
   213→        fixed top-0 right-0 h-screen
   214→        transition-transform duration-200 ease-in-out
   215→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   216→        w-[300px] lg:w-[375px]
   217→        bg-white dark:bg-black
   218→        border-l border-border-light dark:border-border-dark
   219→        shadow-2xl
   220→        z-40
   221→        flex flex-col
   222→      `}
   223→    >
   224→      {/* Header - Terminal Style */}
   225→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   226→        <div className="flex items-center gap-2 font-mono text-sm">
   227→          <span>user@neuman-brain:~$</span>
   228→          <span className="text-text-light-secondary dark:text-text-dark-secondary text-xs">
   229→            {router.getConfiguredProviders().length > 0
   230→              ? `${activeProvider}/${activeModel}`
   231→              : 'no-provider'}
   232→          </span>
   233→        </div>
   234→
   235→        <div className="flex items-center gap-1">
   236→          {/* Fallback indicator */}
   237→          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
   238→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded font-mono" title="Automatic fallback enabled">
   239→              🔄
   240→            </span>
   241→          )}
   242→
   243→          {/* Usage Tracker */}
   244→          <button
   245→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   246→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   247→            title="Usage Statistics"
   248→          >
   249→            📊
   250→          </button>
   251→
   252→          {/* Model Selector */}
   253→          <button
   254→            onClick={() => setShowModelSelector(!showModelSelector)}
   255→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   256→            title="Select Model"
   257→          >
   258→            🔀
   259→          </button>
   260→
   261→          {/* Provider Settings */}
   262→          <button
   263→            onClick={() => setShowProviderSettings(true)}
   264→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   265→            title="Provider Settings"
   266→          >
   267→            ⚙️
   268→          </button>
   269→
   270→          {/* Close */}
   271→          <button
   272→            onClick={() => setOpen(false)}
   273→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-base"
   274→            title="Close Terminal"
   275→          >
   276→            ✕
   277→          </button>
   278→        </div>
   279→      </div>
   280→
   281→      {/* Chat Content */}
   282→      <div className="flex flex-col flex-1 overflow-hidden">
   283→        {/* Messages */}
   284→        <div className="flex-1 overflow-y-auto p-4 space-y-4">
   285→            {/* Fallback Notification */}
   286→            {fallbackNotification && (
   287→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary">
   288→                {fallbackNotification}
   289→              </div>
   290→            )}
   291→
   292→            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
   293→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   294→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
   295→                <p className="text-sm mb-4">
   296→                  Configure AI providers to get started. Choose from 8 providers including free options!
   297→                </p>
   298→                <button
   299→                  onClick={() => setShowProviderSettings(true)}
   300→                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg transition-colors"
   301→                >
   302→                  ⚙️ Configure Providers
   303→                </button>
   304→                <div className="mt-4 text-xs space-y-1">
   305→                  <p className="font-medium">Free Providers Available:</p>
   306→                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
   307→                  <p>• Groq (Lightning-fast inference)</p>
   308→                  <p>• HuggingFace (Thousands of models)</p>
   309→                  <p>• Mistral (European AI)</p>
   310→                </div>
   311→              </div>
   312→            )}
   313→
   314→            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
   315→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   316→                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
   317→                <p className="text-sm mb-2">
   318→                  Active: <span className="font-medium text-accent-blue">{activeProvider}</span> • {activeModel}
   319→                </p>
   320→                <p className="text-sm">Ask me anything! I can help with:</p>
   321→                <ul className="text-sm mt-2 space-y-1">
   322→                  <li>💬 General questions & conversation</li>
   323→                  <li>💻 Code generation & explanation</li>
   324→                  <li>🔧 Debugging & problem solving</li>
   325→                  <li>📝 Writing & productivity</li>
   326→                  <li>🔄 Automatic fallback if provider fails</li>
   327→                </ul>
   328→              </div>
   329→            )}
   330→
   331→            {messages.map((message) => (
   332→              <div
   333→                key={message.id}
   334→                className={`flex gap-3 ${
   335→                  message.role === 'user' ? 'justify-end' : 'justify-start'
   336→                }`}
   337→              >
   338→                {message.role !== 'user' && (
   339→                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   340→                    {message.role === 'system' ? '⚠️' : '🤖'}
   341→                  </div>
   342→                )}
   343→
   344→                <div
   345→                  className={`max-w-[80%] rounded-lg px-4 py-2 font-mono ${
   346→                    message.role === 'user'
   347→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-white'
   348→                      : message.role === 'system'
   349→                      ? 'bg-yellow-100 dark:bg-yellow-900/30 text-text-light-primary dark:text-text-dark-primary border border-yellow-400 dark:border-yellow-600'
   350→                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400'
   351→                  }`}
   352→                >
   353→                  {message.role === 'assistant' ? (
   354→                    <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   355→                      <ReactMarkdown>{message.content}</ReactMarkdown>
   356→                    </div>
   357→                  ) : (
   358→                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
   359→                  )}
   360→                  <div className="flex items-center gap-2 text-xs opacity-60 mt-1">
   361→                    <span>{new Date(message.timestamp).toLocaleTimeString()}</span>
   362→                    {message.provider && message.model && (
   363→                      <>
   364→                        <span>•</span>
   365→                        <span className="font-medium" title="Provider and model used">
   366→                          {message.provider} • {message.model}
   367→                        </span>
   368→                      </>
   369→                    )}
   370→                  </div>
   371→                </div>
   372→
   373→                {message.role === 'user' && (
   374→                  <div className="w-8 h-8 rounded-full bg-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   375→                    👤
   376→                  </div>
   377→                )}
   378→              </div>
   379→            ))}
   380→
   381→            {/* Streaming message */}
   382→            {isStreaming && streamingContent && (
   383→              <div className="flex gap-3 justify-start">
   384→                <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   385→                  🤖
   386→                </div>
   387→                <div className="max-w-[80%] rounded-lg px-4 py-2 font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400">
   388→                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   389→                    <ReactMarkdown>{streamingContent}</ReactMarkdown>
   390→                  </div>
   391→                  <div className="flex items-center gap-1 text-xs opacity-60 mt-1">
   392→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse" />
   393→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-75" />
   394→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-150" />
   395→                  </div>
   396→                </div>
   397→              </div>
   398→            )}
   399→
   400→            <div ref={messagesEndRef} />
   401→          </div>
   402→
   403→          {/* Input Area */}
   404→          <div className="border-t border-border-light dark:border-border-dark p-3 bg-surface-light dark:bg-black flex-shrink-0">
   405→            <form onSubmit={handleSubmit} className="flex gap-2">
   406→              <textarea
   407→                ref={inputRef}
   408→                value={input}
   409→                onChange={(e) => setInput(e.target.value)}
   410→                onKeyDown={handleKeyDown}
   411→                placeholder={
   412→                  router.getConfiguredProviders().length > 0
   413→                    ? 'user@neuman-brain:~$ _'
   414→                    : 'Configure providers first...'
   415→                }
   416→                disabled={router.getConfiguredProviders().length === 0 || isStreaming}
   417→                className="flex-1 px-3 py-2 rounded-lg font-mono text-sm bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark text-text-light-primary dark:text-white placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue dark:focus:ring-green-400 focus:border-transparent resize-none"
   418→                rows={1}
   419→              />
   420→              <button
   421→                type="submit"
   422→                disabled={router.getConfiguredProviders().length === 0 || !input.trim() || isStreaming}
   423→                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 dark:disabled:bg-neutral-700 text-white rounded-lg font-medium transition-colors disabled:cursor-not-allowed"
   424→              >
   425→                {isStreaming ? '⋯' : '→'}
   426→              </button>
   427→              {messages.length > 0 && (
   428→                <button
   429→                  type="button"
   430→                  onClick={clearMessages}
   431→                  className="px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-200 dark:hover:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-lg text-sm transition-colors"
   432→                  title="Clear chat"
   433→                >
   434→                  🗑️
   435→                </button>
   436→              )}
   437→            </form>
   438→          </div>
   439→        </div>
   440→
   441→      {/* Provider Settings Modal */}
   442→      <ProviderSettings
   443→        isOpen={showProviderSettings}
   444→        onClose={() => setShowProviderSettings(false)}
   445→        router={router}
   446→      />
   447→
   448→      {/* Model Selector Sliding Panel */}
   449→      {showModelSelector && (
   450→        <div className="absolute top-12 right-0 w-96 max-h-[400px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
   451→          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
   452→            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   453→              Select Model
   454→            </h3>
   455→            <button
   456→              onClick={() => setShowModelSelector(false)}
   457→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark rounded"
   458→            >
   459→              ✕
   460→            </button>
   461→          </div>
   462→          <div className="p-4 overflow-y-auto max-h-[350px]">
   463→            <ModelSelector
   464→              router={router}
   465→              onSelect={(providerId, modelId) => {
   466→                setActiveProvider(providerId, modelId);
   467→                setShowModelSelector(false);
   468→              }}
   469→              currentProvider={activeProvider}
   470→              currentModel={activeModel}
   471→            />
   472→          </div>
   473→        </div>
   474→      )}
   475→
   476→      {/* Usage Tracker Sliding Panel */}
   477→      {showUsageTracker && (
   478→        <div className="absolute top-12 right-0 w-96 max-h-[500px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
   479→          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
   480→            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   481→              Usage Tracker
   482→            </h3>
   483→            <button
   484→              onClick={() => setShowUsageTracker(false)}
   485→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark rounded"
   486→            >
   487→              ✕
   488→            </button>
   489→          </div>
   490→          <div className="p-4 overflow-y-auto max-h-[450px]">
   491→            <UsageTracker router={router} />
   492→          </div>
   493→        </div>
   494→      )}
   495→    </div>
   496→  );
   497→};
   498→

