import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Widget } from '../components/Widget';
import { useWeatherStore } from '../stores/useWeatherStore';
import { getWeatherIcon } from '../utils/weatherCodes';
import type { WeatherData } from '../types';

interface ForecastDay {
  date: string;
  tempMax: number;
  tempMin: number;
  weatherCode: number;
}

/**
 * Combined Weather & Map Widget
 * Shows weather info as compact header with map below
 */
export const WeatherMap: React.FC = () => {
  const {
    city,
    coords,
    weatherData,
    loading,
    error,
    useGeolocation,
    setCity,
    setCoords,
    setWeatherData,
    setLoading,
    setError,
    setUseGeolocation,
  } = useWeatherStore();

  const [cityInput, setCityInput] = useState(city);
  const [showCityInput, setShowCityInput] = useState(!useGeolocation);
  const [forecast, setForecast] = useState<ForecastDay[]>([]);
  const [forecastLoading, setForecastLoading] = useState(false);
  const mapRef = useRef<HTMLDivElement>(null);
  const leafletMapRef = useRef<L.Map | null>(null);

  // Fetch weather
  const fetchWeather = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(
        `https://api.open-meteo.com/v1/forecast?latitude=${coords.lat}&longitude=${coords.lng}&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m&temperature_unit=fahrenheit&wind_speed_unit=mph&timezone=auto`
      );

      if (!response.ok) throw new Error('Weather API request failed');

      const data = await response.json();

      const weather: WeatherData = {
        location: city || 'Unknown Location',
        temp: Math.round(data.current.temperature_2m),
        desc: getWeatherDescription(data.current.weather_code),
        humidity: data.current.relative_humidity_2m,
        windSpeed: Math.round(data.current.wind_speed_10m),
        icon: getWeatherIcon(data.current.weather_code),
      };

      setWeatherData(weather);
      setLoading(false);
    } catch (err) {
      console.error('Weather fetch error:', err);
      setError('Failed to fetch weather data');
      setLoading(false);
    }
  };

  // Fetch 5-day forecast
  const fetchForecast = useCallback(async () => {
    setForecastLoading(true);

    try {
      const response = await fetch(
        `https://api.open-meteo.com/v1/forecast?latitude=${coords.lat}&longitude=${coords.lng}&daily=temperature_2m_max,temperature_2m_min,weathercode&temperature_unit=fahrenheit&timezone=auto`
      );
      if (!response.ok) throw new Error('Failed to fetch forecast');

      const data = await response.json();
      const days: ForecastDay[] = data.daily.time.slice(0, 5).map((date: string, i: number) => ({
        date,
        tempMax: Math.round(data.daily.temperature_2m_max[i]),
        tempMin: Math.round(data.daily.temperature_2m_min[i]),
        weatherCode: data.daily.weathercode[i],
      }));

      setForecast(days);
    } catch (err) {
      console.error('Forecast fetch error:', err);
    } finally {
      setForecastLoading(false);
    }
  }, [coords.lat, coords.lng]);

  const getUserLocation = async () => {
    if (!navigator.geolocation) {
      setError('Geolocation not supported');
      setUseGeolocation(false);
      return;
    }

    setLoading(true);
    setError(null);

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const newCoords = {
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        };
        setCoords(newCoords);

        const cityName = await reverseGeocode(newCoords.lat, newCoords.lng);
        if (cityName) setCity(cityName);

        setLoading(false);
      },
      (error) => {
        console.error('Geolocation error:', error);
        setError('Could not get location');
        setUseGeolocation(false);
        setShowCityInput(true);
        setLoading(false);
      }
    );
  };

  const reverseGeocode = async (lat: number, lng: number): Promise<string | null> => {
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=10`
      );
      const data = await response.json();
      return data.address?.city || data.address?.town || data.address?.village || data.display_name;
    } catch (error) {
      console.error('Reverse geocoding failed:', error);
      return null;
    }
  };

  const geocodeCity = async (cityName: string): Promise<{ lat: number; lng: number } | null> => {
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(cityName)}&limit=1`
      );
      const data = await response.json();
      if (data.length === 0) return null;

      return {
        lat: parseFloat(data[0].lat),
        lng: parseFloat(data[0].lon),
      };
    } catch (error) {
      console.error('Geocoding failed:', error);
      return null;
    }
  };

  const handleCitySubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!cityInput.trim()) return;

    setLoading(true);
    setError(null);

    const coords = await geocodeCity(cityInput.trim());
    if (!coords) {
      setError(`Could not find "${cityInput}"`);
      setLoading(false);
      return;
    }

    setCity(cityInput.trim());
    setCoords(coords);
    setUseGeolocation(false);
    setShowCityInput(false);
  };

  // Initialize weather
  useEffect(() => {
    fetchWeather();
    // Only reverse geocode if we don't already have a city name
    if (!city) {
      reverseGeocode(coords.lat, coords.lng).then((cityName) => {
        if (cityName) setCity(cityName);
      });
    }

    const interval = setInterval(fetchWeather, 30 * 60 * 1000);
    return () => clearInterval(interval);
  }, [coords.lat, coords.lng]);

  // Initialize map
  useEffect(() => {
    if (!mapRef.current || leafletMapRef.current) return;

    // @ts-ignore - Leaflet is loaded globally via CDN
    const L = window.L;
    if (!L) {
      console.error('Leaflet not loaded');
      return;
    }

    // Initialize map
    const map = L.map(mapRef.current).setView([coords.lat, coords.lng], 10);

    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap contributors',
      maxZoom: 19,
    }).addTo(map);

    L.marker([coords.lat, coords.lng])
      .addTo(map)
      .bindPopup(city || 'Your Location')
      .openPopup();

    leafletMapRef.current = map;

    // Cleanup
    return () => {
      if (leafletMapRef.current) {
        leafletMapRef.current.remove();
        leafletMapRef.current = null;
      }
    };
  }, []);

  // Update map when coordinates change
  useEffect(() => {
    if (leafletMapRef.current) {
      // @ts-ignore
      const L = window.L;
      if (L) {
        leafletMapRef.current.setView([coords.lat, coords.lng], 10);
        leafletMapRef.current.eachLayer((layer) => {
          // @ts-ignore
          if (layer instanceof L.Marker) {
            leafletMapRef.current?.removeLayer(layer);
          }
        });
        L.marker([coords.lat, coords.lng])
          .addTo(leafletMapRef.current)
          .bindPopup(city || 'Your Location')
          .openPopup();
      }
    }
  }, [coords.lat, coords.lng, city]);

  // Auto-fetch forecast on mount and when coords change
  useEffect(() => {
    if (coords.lat && coords.lng) {
      fetchForecast();
    }
  }, [coords.lat, coords.lng, fetchForecast]);

  // Compact weather stats display for header
  const weatherStatsDisplay = (
    <div className="flex items-center gap-2 text-sm">
      {/* Weather Stats */}
      {weatherData && !loading ? (
        <>
          {/* Weather icon and temp */}
          <div className="flex items-center gap-2">
            <div className="text-2xl">{weatherData.icon}</div>
            <div className="font-bold text-xl text-text-light-primary dark:text-text-dark-primary">
              {weatherData.temp}°F
            </div>
          </div>

          {/* Additional stats */}
          <div className="flex gap-3 text-xs">
            <span className="text-text-light-secondary dark:text-text-dark-secondary">
              💧 {weatherData.humidity}%
            </span>
            <span className="text-text-light-secondary dark:text-text-dark-secondary">
              💨 {weatherData.windSpeed} mph
            </span>
          </div>

          {/* Location name */}
          <div className="h-6 w-px bg-neutral-300 dark:bg-neutral-600"></div>
          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
            📍 {city || 'Unknown Location'}
          </span>
        </>
      ) : loading ? (
        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">Loading...</div>
      ) : null}
    </div>
  );

  return (
    <Widget
      id="weathermap"
      title="Weather & Location"
      headerAccessory={weatherStatsDisplay}
      draggable={false}
    >
      <div className="weathermap-widget flex flex-col lg:flex-row gap-4 h-full">
        {/* Left: Map Section (auto-expands to fill remaining space) */}
        <div className="map-section flex-1 min-h-[320px] lg:min-h-[400px]">
          <div className="map-container relative w-full h-full rounded-xl overflow-hidden">
            <div
              ref={mapRef}
              className="absolute inset-0 z-0"
              onMouseDown={(e) => e.stopPropagation()}
              onTouchStart={(e) => e.stopPropagation()}
            />

            {/* Error message overlay - Centered on map */}
            {error && (
              <div className="absolute top-4 left-4 right-4 z-10 mx-auto max-w-md">
                <div className="p-4 bg-red-50 dark:bg-red-900/30 border-2 border-red-400 dark:border-red-600 rounded-lg shadow-xl text-sm text-red-800 dark:text-red-300 font-medium">
                  ⚠️ {error}
                </div>
              </div>
            )}

            {/* Location Controls - Overlay on map (top-left) */}
            {showCityInput ? (
              <div className="absolute top-4 left-4 z-10 flex gap-2 max-w-[280px]">
                <form onSubmit={handleCitySubmit} className="flex gap-2 flex-1 min-w-0">
                  <input
                    type="text"
                    value={cityInput}
                    onChange={(e) => setCityInput(e.target.value)}
                    placeholder="Enter city..."
                    className="flex-1 min-w-0 px-3 py-2 text-sm border border-neutral-300 dark:border-neutral-600 rounded-lg bg-white dark:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-cyan shadow-lg"
                  />
                  <button
                    type="submit"
                    className="px-3 py-2 text-sm bg-accent-cyan text-white rounded-lg hover:bg-accent-cyan-hover shadow-lg"
                    disabled={loading}
                  >
                    {loading ? '...' : 'Go'}
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setShowCityInput(false);
                      getUserLocation();
                    }}
                    className="px-3 py-2 text-sm bg-white dark:bg-neutral-600 text-text-light-secondary dark:text-text-dark-secondary rounded-lg hover:opacity-80 shadow-lg"
                    title="Use my location"
                  >
                    📍
                  </button>
                </form>
              </div>
            ) : (
              <button
                onClick={() => setShowCityInput(true)}
                className="absolute top-4 left-4 z-10 px-3 py-2 text-sm bg-white dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark hover:text-accent-cyan transition-colors rounded-lg shadow-lg border border-border-light dark:border-border-dark"
              >
                📍 {city || 'Set Location'} ✏️
              </button>
            )}

            {/* GPS Location Button - Overlay on map (bottom-right) */}
            <button
              onClick={getUserLocation}
              disabled={loading}
              className="absolute bottom-4 right-4 z-10 p-3 bg-white dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary rounded-full shadow-lg hover:shadow-xl transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed border border-border-light dark:border-border-dark hover:scale-110"
              title="Use my current location"
            >
              <span className="text-2xl">📍</span>
            </button>
          </div>
        </div>

        {/* Right: 5-Day Forecast Section (auto-width based on content) */}
        <div className="forecast-section flex-shrink-0 min-h-[240px] lg:min-h-[400px] overflow-y-auto">
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3 text-right">
            5-Day Forecast
          </h3>
          {forecastLoading ? (
            <div className="flex items-center justify-center h-32">
              <p className="text-text-light-secondary dark:text-text-dark-secondary">Loading forecast...</p>
            </div>
          ) : forecast.length > 0 ? (
            <div className="space-y-2 flex flex-col items-end">
              {forecast.map((day) => (
                <div
                  key={day.date}
                  className="flex items-center gap-3 p-2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg hover:bg-surface-light dark:hover:bg-surface-dark transition-colors w-64"
                >
                  <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary w-24">
                    {formatDate(day.date)}
                  </span>
                  <span className="text-2xl w-8 text-center">{getWeatherIcon(day.weatherCode)}</span>
                  <div className="text-sm flex-1">
                    <div className="font-semibold text-text-light-primary dark:text-text-dark-primary whitespace-nowrap text-right">
                      {day.tempMax}° / {day.tempMin}°F
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="flex items-center justify-center h-32">
              <p className="text-text-light-secondary dark:text-text-dark-secondary">No forecast data available</p>
            </div>
          )}
        </div>
      </div>
    </Widget>
  );
};

function formatDate(dateStr: string): string {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
}

function getWeatherDescription(code: number): string {
  const descriptions: Record<number, string> = {
    0: 'Clear',
    1: 'Mostly Clear',
    2: 'Partly Cloudy',
    3: 'Overcast',
    45: 'Foggy',
    48: 'Foggy',
    51: 'Light Drizzle',
    53: 'Drizzle',
    55: 'Heavy Drizzle',
    61: 'Light Rain',
    63: 'Rain',
    65: 'Heavy Rain',
    71: 'Light Snow',
    73: 'Snow',
    75: 'Heavy Snow',
    77: 'Snow Grains',
    80: 'Rain Showers',
    81: 'Rain Showers',
    82: 'Heavy Rain Showers',
    85: 'Snow Showers',
    86: 'Heavy Snow Showers',
    95: 'Thunderstorm',
    96: 'Thunderstorm',
    99: 'Severe Thunderstorm',
  };
  return descriptions[code] || 'Unknown';
}

