   110→              title="Drag to reorder"
   111→            >
   112→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">⋮⋮</span>
   113→            </div>
   114→          </>
   115→        )}
   116→
   117→        {/* Tooltip for collapsed state */}
   118→        {isCollapsed && (
   119→          <div className="
   120→            absolute left-full ml-2 px-2 py-1
   121→            bg-surface-dark text-text-dark-primary text-xs rounded
   122→            opacity-0 group-hover:opacity-100
   123→            pointer-events-none transition-opacity duration-200
   124→            whitespace-nowrap z-50
   125→          ">
