   127→          </div>
   128→        )}
   129→      </Link>
   130→    </li>
   131→  );
   132→};
   133→
   134→export const Sidebar: React.FC = () => {
   135→  const { isCollapsed, toggleCollapse, isMobileMenuOpen, setMobileMenuOpen } = useSidebarStore();
   136→  const { mode, toggleTheme } = useThemeStore();
   137→  const navOrder = useSidebarNavStore((state) => state.navOrder);
   138→  const setNavOrder = useSidebarNavStore((state) => state.setNavOrder);
   139→  const location = useLocation();
   140→  const [pageSettingsOpen, setPageSettingsOpen] = useState<string | null>(null);
   141→
   142→  const isActive = (path: string) => location.pathname === path;
   143→
   144→  // Configure drag sensors (require 5px movement to start dragging)
   145→  const sensors = useSensors(
   146→    useSensor(PointerSensor, {
   147→      activationConstraint: {
   148→        distance: 5,
   149→      },
   150→    })
   151→  );
   152→
   153→  // Sort draggable navigation items by saved order
   154→  const sortedDraggableNavigation = [...draggableNavigation].sort((a, b) => {
   155→    const aIndex = navOrder.indexOf(a.path);
   156→    const bIndex = navOrder.indexOf(b.path);
   157→    // If path not found in order, put it at the end
   158→    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex);
   159→  });
   160→
   161→  const handleDragEnd = (event: DragEndEvent) => {
   162→    const { active, over } = event;
   163→
   164→    if (over && active.id !== over.id) {
   165→      const oldIndex = navOrder.indexOf(active.id as string);
   166→      const newIndex = navOrder.indexOf(over.id as string);
   167→
   168→      if (oldIndex !== -1 && newIndex !== -1) {
   169→        const newOrder = arrayMove(navOrder, oldIndex, newIndex);
   170→        setNavOrder(newOrder);
   171→      }
   172→    }
   173→  };
   174→
   175→  const handlePageSettings = (e: React.MouseEvent, path: string) => {
   176→    e.preventDefault();
   177→    e.stopPropagation();
   178→    setPageSettingsOpen(path);
   179→  };
   180→
   181→  // Close mobile menu on route change
   182→  useEffect(() => {
   183→    setMobileMenuOpen(false);
   184→  }, [location.pathname, setMobileMenuOpen]);
   185→
   186→  // Keyboard shortcut: Cmd/Ctrl + B to toggle
   187→  useEffect(() => {
   188→    const handleKeyDown = (e: KeyboardEvent) => {
