import React from 'react';
import { motion } from 'framer-motion';
import { formatDistanceToNow } from 'date-fns';
import { useSaveStatus } from '../stores/useSaveStatus';

/**
 * Footer component with save status indicator
 * Sticky footer at bottom-right showing real-time save status
 */
export const Footer: React.FC = () => {
  const { status, lastSaveTime } = useSaveStatus();

  // Simplified status text
  const getStatusText = () => {
    switch (status) {
      case 'saving':
        return 'Saving...';
      case 'saved':
        return lastSaveTime ? formatDistanceToNow(lastSaveTime, { addSuffix: true }) : 'Saved';
      case 'error':
        return 'Failed';
      default:
        return 'Saved';
    }
  };

  return (
    <motion.footer
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3, ease: [0.4, 0, 0.2, 1] }}
      className="fixed bottom-20 right-4 z-20 pointer-events-none"
    >
      <div className="flex items-center gap-2 px-4 py-2 bg-white/90 dark:bg-surface-dark/90 backdrop-blur-lg rounded-full shadow-lg border border-border-light dark:border-border-dark pointer-events-auto">
        {/* Status Dot */}
        <span
          className={`w-2.5 h-2.5 rounded-full ${
            status === 'saving'
              ? 'bg-blue-500 animate-pulse'
              : status === 'saved'
              ? 'bg-green-500'
              : status === 'error'
              ? 'bg-red-500'
              : 'bg-neutral-400'
          }`}
        />

        {/* Status Text */}
        <span className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary">
          {getStatusText()}
        </span>
      </div>
    </motion.footer>
  );
};

