     9→  defaultColumn?: string;
    10→}
    11→
    12→/**
    13→ * QuickAddModal - Quick task creation with Cmd/Ctrl+K
    14→ * Phase A: Quick Wins - Quick Add Feature
    15→ *
    16→ * Features:
    17→ * - Keyboard-first design (Cmd/Ctrl+K to open)
    18→ * - Smart defaults (remembers last used column and priority)
    19→ * - Minimal UI (title + optional details)
    20→ * - Instant creation (no detail panel needed)
    21→ */
    22→export function QuickAddModal({ isOpen, onClose, defaultColumn }: QuickAddModalProps) {
    23→  const { addTask, columns } = useKanbanStore();
    24→
    25→  // Form state
    26→  const [title, setTitle] = useState('');
    27→  const [description, setDescription] = useState('');
    28→  const [column, setColumn] = useState(() => {
    29→    if (defaultColumn) return defaultColumn;
    30→    const saved = localStorage.getItem('kanban-quick-add-column');
    31→    return saved || 'todo';
    32→  });
    33→  const [priority, setPriority] = useState<TaskPriority>(() => {
    34→    const saved = localStorage.getItem('kanban-quick-add-priority');
    35→    return (saved as TaskPriority) || 'medium';
    36→  });
    37→  const [dueDate, setDueDate] = useState('');
    38→
    39→  // Reset form when modal opens
    40→  useEffect(() => {
    41→    if (isOpen) {
    42→      setTitle('');
    43→      setDescription('');
    44→      setDueDate('');
    45→      // Keep column and priority (smart defaults)
    46→    }
    47→  }, [isOpen]);
    48→
    49→  // Save preferences when changed
