    64→      if (e.key === 'Escape') {
    65→        onClose();
    66→      }
    67→
    68→      // Cmd/Ctrl+Enter to submit
    69→      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
    70→        e.preventDefault();
    71→        handleSubmit();
    72→      }
    73→    };
    74→
    75→    window.addEventListener('keydown', handleKeyDown);
    76→    return () => window.removeEventListener('keydown', handleKeyDown);
    77→  }, [isOpen, onClose, title, column, priority, description, dueDate]);
    78→
    79→  const handleSubmit = useCallback(() => {
    80→    if (!title.trim()) return;
    81→
    82→    addTask({
    83→      title: title.trim(),
    84→      description: description.trim(),
    85→      status: column as any,
    86→      priority,
    87→      startDate: null,
    88→      dueDate: dueDate || null,
    89→      tags: [],
    90→    });
    91→
    92→    onClose();
    93→  }, [title, description, column, priority, dueDate, addTask, onClose]);
    94→
    95→  if (!isOpen) return null;
    96→
    97→  return (
    98→    <AnimatePresence>
    99→      <div className="fixed inset-0 z-50 flex items-start justify-center pt-20">
   100→        {/* Backdrop */}
   101→        <motion.div
   102→          initial={{ opacity: 0 }}
   103→          animate={{ opacity: 1 }}
   104→          exit={{ opacity: 0 }}
   105→          className="absolute inset-0 bg-black/50"
   106→          onClick={onClose}
   107→        />
   108→
   109→        {/* Modal */}
   110→        <motion.div
   111→          initial={{ opacity: 0, scale: 0.95, y: -20 }}
   112→          animate={{ opacity: 1, scale: 1, y: 0 }}
   113→          exit={{ opacity: 0, scale: 0.95, y: -20 }}
   114→          className="relative w-full max-w-2xl mx-4 bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-2xl border border-border-light dark:border-border-dark overflow-hidden"
   115→        >
   116→          {/* Header */}
   117→          <div className="flex items-center justify-between px-6 py-4 border-b border-border-light dark:border-border-dark">
   118→            <div className="flex items-center gap-2">
   119→              <span className="text-xl">⚡</span>
   120→              <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
   121→                Quick Add Task
   122→              </h2>
   123→            </div>
   124→            <button
   125→              onClick={onClose}
   126→              className="p-2 rounded-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
   127→              aria-label="Close"
   128→            >
   129→              <span className="text-2xl text-text-light-secondary dark:text-text-dark-secondary">×</span>
   130→            </button>
   131→          </div>
   132→
   133→          {/* Form */}
   134→          <div className="p-6 space-y-4">
   135→            {/* Title (auto-focused) */}
   136→            <div>
   137→              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   138→                Task Title *
   139→              </label>
   140→              <input
   141→                type="text"
   142→                value={title}
   143→                onChange={(e) => setTitle(e.target.value)}
   144→                placeholder="What needs to be done?"
   145→                className="w-full px-4 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-secondary dark:placeholder:text-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue"
